import React, { useState } from 'react';
import { Phone, MapPin, MessageSquare, Plus } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

export default function FloatingActions() {
  const [isOpen, setIsOpen] = useState(false);

  const actions = [
    { icon: <Phone size={18} />, label: "Call", color: "bg-blue-500" },
    { icon: <MapPin size={18} />, label: "Map", color: "bg-red-500" },
    { icon: <MessageSquare size={18} />, label: "Chat", color: "bg-green-500" },
  ];

  return (
    <div className="fixed bottom-10 right-10 z-[100]">
      <AnimatePresence>
        {isOpen && (
          <div className="flex flex-col-reverse gap-4 mb-4">
            {actions.map((action, i) => (
              <motion.button
                key={i}
                initial={{ opacity: 0, scale: 0 }}
                animate={{ opacity: 1, scale: 1 }}
                exit={{ opacity: 0, scale: 0 }}
                transition={{ delay: i * 0.1 }}
                className={`${action.color} text-white p-4 rounded-full shadow-lg hover:scale-110 transition-transform`}
              >
                {action.icon}
              </motion.button>
            ))}
          </div>
        )}
      </AnimatePresence>
      <button 
        onClick={() => setIsOpen(!isOpen)}
        className="bg-luxury-gold text-white p-5 rounded-full shadow-2xl rotate-interaction"
      >
        <Plus className={`transition-transform duration-300 ${isOpen ? 'rotate-45' : 'rotate-0'}`} />
      </button>
    </div>
  );
}
